"use client";

import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";
import { useEffect } from "react";
import { auth } from "@/lib/firebase";

export default function Dashboard() {
    const { user } = useAuth();

    return (
        <div>
            <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', marginBottom: '1.5rem', color: 'var(--primary)' }}>
                Overview
            </h1>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1.5rem' }}>
                <DashboardCard title="Active Requests" value="12" icon="📝" />
                <DashboardCard title="Pending Approval" value="5" icon="⏳" />
                <DashboardCard title="Total Spend (YTD)" value="$45,200" icon="💰" />
                <DashboardCard title="Active Vendors" value="28" icon="🏢" />
            </div>

            <div style={{ marginTop: '2rem' }}>
                <h2 style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '1rem' }}>Recent Activity</h2>
                <div className="card">
                    <p style={{ color: 'var(--text-secondary)', padding: '1rem', textAlign: 'center' }}>No recent activity to show.</p>
                </div>
            </div>
        </div>
    );
}

function DashboardCard({ title, value, icon }: { title: string, value: string, icon: string }) {
    return (
        <div className="card" style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
            <div style={{
                width: '48px',
                height: '48px',
                borderRadius: 'var(--radius-md)',
                backgroundColor: 'var(--background)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: '1.5rem'
            }}>
                {icon}
            </div>
            <div>
                <div style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>{title}</div>
                <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--primary)' }}>{value}</div>
            </div>
        </div>
    );
}
